import { connect, useDispatch } from 'react-redux';

import { setOnBoardingModalsVisibility, setOnBoardingVisible } from '../../../reduxStore/actions/modalsActions';
import cls from './Company.module.scss';
import { CompanyOverview } from '../CompanyComps/CompanyCards';
import CompanySettings from '../../TopBar/CompanySettings/CompanySettings';
import HeaderTopBar from '../../common/HeaderTopBar/HeaderTopBar';
import { PermissionWrapper, po } from '../../common';
import { useEffect } from 'react';
import { setShowMenu, setShowSideMenu } from '../../../reduxStore/actions/flowActions';
import { APP_NAME } from '../../../shared/utility';

const CompanyHome = props => {
	const { companyData, authenticatedUser } = props;
	const dispatch = useDispatch();

	document.title = `Company | ${APP_NAME}`;

	useEffect(() => {
		dispatch(setShowSideMenu(false));
		dispatch(setShowMenu(false));
	}, []);

	return (
		<div className={cls.companyHost}>
			<div style={{ display: 'flex', flexDirection: 'column', margin: '80px 0 0 0' }}>
				<HeaderTopBar headerTitle={`Home Page of ${companyData.name}`} targetProcessing={false} />
			</div>
		 </div>
	);
};

const mapStateToProps = store => {
	const {
		authenticatedUser: { position },
		authenticatedUser,
	} = store.authReducer;
	const { user } = store.sessionReducer;

	const { companyData, companyPositionsArray, allTasks, allCompletedTasks, allCompletedTasksPaginated, companyUsersArray } = store.flowReducer;
	return {
		companyData,
		companyPositionsArray,
		position,
		allTasks,
		allCompletedTasks,
		allCompletedTasksPaginated,
		user,
		companyUsersArray,
		authenticatedUser,
	};
};

const mapDispatchToProps = dispatch => {
	return {
		onSetOnBoardingVisible: visible => dispatch(setOnBoardingVisible(visible)),
		onToggleModalVisibility: modalVisible => dispatch(setOnBoardingModalsVisibility(modalVisible)),
	};
};
export default connect(mapStateToProps, mapDispatchToProps)(CompanyHome);
